tool.validation_logic:

def validate_subject_length(subject_line):
    """
    Validates subject line length for mobile display.
    Mobile email clients typically show first 50-60 characters.

    Returns:
        dict: {
            'valid': bool,
            'length': int,
            'message': str,
            'recommendation': str (if exceeds)
        }
    """
    length = len(subject_line)

    if length <= 60:
        return {
            'valid': True,
            'length': length,
            'message': f'Subject line length OK: {length}/60 characters'
        }
    else:
        return {
            'valid': False,
            'length': length,
            'message': f'Subject line too long: {length}/60 characters',
            'recommendation': 'Shorten to ≤60 chars for mobile display'
        }
